import{_ as i,o as a,c as t,ag as o}from"./chunks/framework.CXIqMST4.js";const p=JSON.parse('{"title":"Skills、Automations 与团队沉淀","description":"","frontmatter":{},"headers":[],"relativePath":"guide/08-skills-automations.md","filePath":"guide/08-skills-automations.md","lastUpdated":1777684488000}'),e={name:"guide/08-skills-automations.md"};function s(n,l,r,u,d,c){return a(),t("div",null,[...l[0]||(l[0]=[o('<h1 id="skills、automations-与团队沉淀" tabindex="-1">Skills、Automations 与团队沉淀 <a class="header-anchor" href="#skills、automations-与团队沉淀" aria-label="Permalink to &quot;Skills、Automations 与团队沉淀&quot;">​</a></h1><p>当团队开始稳定使用 Codex 后，真正的收益来自复用：把做得好的流程沉淀下来。</p><h2 id="skills" tabindex="-1">Skills <a class="header-anchor" href="#skills" aria-label="Permalink to &quot;Skills&quot;">​</a></h2><p>Skills 适合固化一类任务的做法，例如：</p><ul><li>代码审查标准。</li><li>文档生成规范。</li><li>发布说明格式。</li><li>数据分析流程。</li><li>特定框架的迁移步骤。</li></ul><p>一个好的 Skill 应该包含：</p><ul><li>触发场景。</li><li>输入要求。</li><li>操作步骤。</li><li>验证方式。</li><li>禁止事项。</li></ul><h2 id="automations" tabindex="-1">Automations <a class="header-anchor" href="#automations" aria-label="Permalink to &quot;Automations&quot;">​</a></h2><p>Automations 适合周期性、重复性或需要提醒的任务，例如：</p><ul><li>每周检查过期依赖。</li><li>定期整理 issue。</li><li>监控 CI 失败。</li><li>提醒更新文档。</li><li>汇总仓库近期变更。</li></ul><h2 id="团队知识库" tabindex="-1">团队知识库 <a class="header-anchor" href="#团队知识库" aria-label="Permalink to &quot;团队知识库&quot;">​</a></h2><p>建议沉淀三类内容：</p><ul><li><code>AGENTS.md</code>：项目级规则。</li><li><code>recipes/</code>：可复用案例。</li><li><code>troubleshooting</code>：失败模式和处理方式。</li></ul><p>每次 Codex 成功解决一个典型问题，都可以把任务说明、关键步骤和验证命令整理成案例。长期看，这比单次“让 AI 写代码”更有复利。</p>',14)])])}const h=i(e,[["render",s]]);export{p as __pageData,h as default};
